    /**
     * Escapes a shell argument to prevent command injection vulnerabilities.
     * Uses single-quote escaping which is the safest method for shell arguments.
     * 
     * @param argument The argument to escape
     * @return The escaped argument safe for use in shell commands
     */
    private String escapeShellArgument(String argument) {
        if (argument == null) {
            return "''";
        }
        // Replace each single quote with '\'' (end quote, escaped quote, restart quote)
        return "'" + argument.replace("'", "'\\''") + "'";
    }
}
